const stripCites = (text) => {
  if (!text) return text;
  return text
    .replace(/<cite[^>]*>/g, "")
    .replace(/<\/cite>/g, "")
    .replace(/&lt;cite[^&]*&gt;/g, "")
    .replace(/&lt;\/cite&gt;/g, "")
    .trim();
};

const Ico = ({ d, s = 22, c = "currentColor" }) => (
  <svg width={s} height={s} viewBox="0 0 24 24" fill={c}>
    <path d={d} />
  </svg>
);

