const BNav = ({ active, go }) => {
  const tabs = [
    { id: "scan", label: "Scan", d: P.scan },
    { id: "result", label: "Result", d: P.result },
    { id: "history", label: "History", d: P.hist },
    { id: "profile", label: "Profile", d: P.prof },
  ];
  return (
    <div
      style={{
        position: "fixed",
        bottom: 0,
        left: "50%",
        transform: "translateX(-50%)",
        width: "100%",
        maxWidth: 430,
        background: "rgba(7,10,15,0.97)",
        backdropFilter: "blur(24px)",
        borderTop: "1px solid rgba(255,255,255,0.07)",
        display: "flex",
        padding: "8px 12px 22px",
        gap: 6,
        zIndex: 100,
      }}
    >
      {tabs.map((t) => {
        const on = active === t.id;
        return (
          <button
            key={t.id}
            onClick={() => go(t.id)}
            style={{
              flex: 1,
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: 5,
              background: on ? "rgba(200,255,0,0.08)" : "transparent",
              border: on
                ? "1px solid rgba(200,255,0,0.2)"
                : "1px solid transparent",
              borderRadius: 12,
              cursor: "pointer",
              padding: "8px 4px",
              color: on ? "#c8ff00" : "#5a6475",
              transition: "all .2s",
            }}
          >
            <Ico d={t.d} s={19} c={on ? "#c8ff00" : "#5a6475"} />
            <span
              style={{
                fontFamily: "var(--mono)",
                fontSize: 8,
                letterSpacing: 1.5,
                textTransform: "uppercase",
                fontWeight: on ? 600 : 400,
              }}
            >
              {t.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

