/* ══════════════════════════════════════════
   SCAN
══════════════════════════════════════════ */
function ScanScreen({ go, setResult, scansUsed, setScansUsed }) {
  const [mode, setMode] = useState("text");
  const [text, setText] = useState("");
  const [url, setUrl] = useState("");
  const [chips, setChips] = useState({
    "Fact-Check": true,
    "Source Check": true,
    "Bias Detect": false,
    "Tone Analysis": false,
  });
  const [step, setStep] = useState(-1);
  const [recording, setRecording] = useState(false);
  const [audioName, setAudioName] = useState("");
  const [scanError, setScanError] = useState("");
  const mediaRef = useRef(null);
  const fileRef = useRef(null);
  const MAX_SCANS = 5;

  const STEPS = [
    "Parsing Content",
    "Cross-referencing Sources",
    "Analyzing Patterns",
    "Generating Report",
  ];
  const API_URL = "/api/analyze";

  const analyzeLocally = (input) => {
    const t = input.toLowerCase();
    const hasURL = !!input.match(/https?:\/\//);
    const fakeWords = [
      "fake",
      "hoax",
      "false",
      "fabricated",
      "debunked",
      "conspiracy",
      "lie",
      "lies",
      "made up",
      "not true",
      "never happened",
      "proven false",
    ];
    const sourceWords = [
      "according to",
      "reported by",
      "study shows",
      "researchers",
      "scientists",
      "experts",
      "data shows",
      "published",
      "journal",
      "university",
      "reuters",
      "bbc",
      "cdc",
      "who",
    ];
    const fakeHits = fakeWords.filter((w) => t.includes(w)).length;
    const sourceHits = sourceWords.filter((w) => t.includes(w)).length;
    const factScore = Math.min(
      100,
      Math.max(
        0,
        fakeHits * 22 - sourceHits * 15 + (t.split(" ").length < 15 ? 30 : 0)
      )
    );
    const alarmWords = [
      "shocking",
      "outrage",
      "unbelievable",
      "explosive",
      "bombshell",
      "disgusting",
      "terrifying",
      "they don't want you to know",
      "wake up",
      "censored",
      "suppressed",
      "mainstream media",
      "deep state",
      "elite",
      "agenda",
      "viral",
      "breaking",
      "deleted",
    ];
    const calmWords = [
      "analysis",
      "however",
      "although",
      "evidence suggests",
      "on the other hand",
      "balanced",
      "context",
      "nuanced",
    ];
    const alarmHits = alarmWords.filter((w) => t.includes(w)).length;
    const calmHits = calmWords.filter((w) => t.includes(w)).length;
    const emotionScore = Math.min(
      100,
      Math.max(0, alarmHits * 18 - calmHits * 12)
    );
    const credibleDomains = [
      "reuters",
      "bbc",
      "npr",
      "nature.com",
      "pubmed",
      "cdc.gov",
      "who.int",
      ".gov",
      ".edu",
      "nytimes",
      "washingtonpost",
      "guardian",
      "apnews",
    ];
    const suspectDomains = [
      "blogspot",
      "wordpress.com",
      "weebly",
      "wixsite",
      "xyz",
      "viral",
      "buzz",
    ];
    const urlMatch = input.match(/https?:\/\/([^\s/]+)/g) || [];
    const domainStr = urlMatch.join(" ").toLowerCase();
    const credHits = credibleDomains.filter(
      (d) => domainStr.includes(d) || t.includes(d)
    ).length;
    const suspectHits = suspectDomains.filter((d) =>
      domainStr.includes(d)
    ).length;
    const sourceScore = hasURL
      ? Math.min(100, Math.max(0, suspectHits * 25 - credHits * 20))
      : 50;
    const capsWords = (input.match(/\b[A-Z]{3,}\b/g) || []).length;
    const excl = (input.match(/!/g) || []).length;
    const styleScore = Math.min(100, Math.max(0, capsWords * 8 + excl * 10));
    const rawScore = Math.round(
      factScore * 0.35 +
        emotionScore * 0.25 +
        sourceScore * 0.25 +
        styleScore * 0.15
    );
    const score = Math.min(97, Math.max(4, rawScore));
    const type = score >= 65 ? "danger" : score >= 35 ? "warn" : "safe";
    const lvl = (s) => (s >= 65 ? "danger" : s >= 35 ? "warn" : "safe");
    return {
      type,
      score,
      title:
        type === "danger"
          ? "High Misinformation Risk"
          : type === "warn"
          ? "Requires Verification"
          : "Appears Credible",
      desc:
        type === "danger"
          ? "Multiple misinformation indicators detected. Do not share without fact-checking."
          : type === "warn"
          ? "Some claims unverified. Cross-check with trusted sources before sharing."
          : "Content shows characteristics of credible reporting.",
      verdict:
        type === "danger" ? "fake" : type === "warn" ? "misleading" : "real",
      summary:
        type === "danger"
          ? "Strong indicators of misinformation detected in this content."
          : type === "warn"
          ? "This content requires additional verification before sharing."
          : "Content appears credible based on available signals.",
      signals: [
        {
          name: "Claim Accuracy",
          desc:
            fakeHits > 0
              ? `${fakeHits} misinformation keyword(s) detected.`
              : sourceHits > 0
              ? `${sourceHits} credible source reference(s) found.`
              : "No explicit fact-check signals. Manual review advised.",
          pct: `${Math.round(100 - factScore)}%`,
          col: ["#ff3b5c", "#ffb340", "#00e676"][
            ["danger", "warn", "safe"].indexOf(lvl(factScore))
          ],
          dot: ["#ff3b5c", "#ffb340", "#00e676"][
            ["danger", "warn", "safe"].indexOf(lvl(factScore))
          ],
        },
        {
          name: "Source Credibility",
          desc: !hasURL
            ? "No source URL provided — credibility not evaluated for this scan."
            : credHits > 0
            ? `References to ${credHits} credible domain(s) found.`
            : "Source domain could not be verified.",
          pct: !hasURL ? "N/A" : `${Math.round(100 - sourceScore)}%`,
          col: !hasURL
            ? "#5a6475"
            : ["#ff3b5c", "#ffb340", "#00e676"][
                ["danger", "warn", "safe"].indexOf(lvl(sourceScore))
              ],
          dot: !hasURL
            ? "#5a6475"
            : ["#ff3b5c", "#ffb340", "#00e676"][
                ["danger", "warn", "safe"].indexOf(lvl(sourceScore))
              ],
        },
        {
          name: "Emotional Intensity",
          desc:
            alarmHits > 0
              ? `${alarmHits} sensational phrase(s) detected.`
              : calmHits > 0
              ? "Balanced, measured language detected."
              : "Neutral tone with no strong emotional markers.",
          pct: `${Math.round(100 - emotionScore)}%`,
          col: ["#ff3b5c", "#ffb340", "#00e676"][
            ["danger", "warn", "safe"].indexOf(lvl(emotionScore))
          ],
          dot: ["#ff3b5c", "#ffb340", "#00e676"][
            ["danger", "warn", "safe"].indexOf(lvl(emotionScore))
          ],
        },
        {
          name: "Writing Style",
          desc:
            capsWords > 2 || excl > 2
              ? `${capsWords} ALL-CAPS word(s) and ${excl} exclamation(s) — sensationalist pattern.`
              : "Writing style consistent with professional standards.",
          pct: `${Math.round(100 - styleScore)}%`,
          col: ["#ff3b5c", "#ffb340", "#00e676"][
            ["danger", "warn", "safe"].indexOf(lvl(styleScore))
          ],
          dot: ["#ff3b5c", "#ffb340", "#00e676"][
            ["danger", "warn", "safe"].indexOf(lvl(styleScore))
          ],
        },
      ],
    };
  };

  const finalize = (analysis, inputVal) => {
    const scanId = "#" + Math.random().toString(36).substr(2, 6).toUpperCase();
    const timestamp = new Date().toLocaleString("en-US", {
      month: "short",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
    });
    setScansUsed((n) => Math.min(n + 1, MAX_SCANS));
    setResult({ ...analysis, input: inputVal, scanId, timestamp });
    go("result");
  };

  const runAnalysis = async (inputType, inputVal) => {
    if (scansUsed >= MAX_SCANS) {
      alert("Daily limit reached (5/5). Upgrade for unlimited scans.");
      return;
    }
    setStep(0);
    let idx = 0;
    const iv = setInterval(() => {
      idx++;
      if (idx < STEPS.length) setStep(idx);
    }, 900);

    // AUDIO MODE — send base64 audio to backend
    if (inputType === "audio") {
      try {
        let audioB64 = null;
        if (audioBlobRef.current) {
          const buf = await audioBlobRef.current.arrayBuffer();
          audioB64 = btoa(String.fromCharCode(...new Uint8Array(buf)));
        }
        const ctrl = new AbortController();
        const t = setTimeout(() => ctrl.abort(), 20000); // 20s for audio
        const res = await fetch(API_URL, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ mode: "audio", audio: audioB64 }),
          signal: ctrl.signal,
        });
        clearTimeout(t);
        if (res.ok) {
          const d = await res.json();
          clearInterval(iv);
          setStep(3);
          setTimeout(() => {
            setStep(-1);
            finalize(d, "[Audio Recording]");
          }, 400);
          return;
        }
      } catch (e) {}
      // Audio fallback
      clearInterval(iv);
      setStep(3);
      setTimeout(() => {
        setStep(-1);
        finalize(
          {
            type: "warn",
            score: 45,
            verdict: "unverified",
            title: "Voice Analysis Unavailable",
            desc: "Backend not configured for audio analysis. Deploy Vercel backend with ELEVENLABS_API_KEY to enable real AI voice detection.",
            summary: "Voice AI detection requires backend configuration.",
            signals: [
              {
                name: "Voice Origin",
                desc: "ElevenLabs API key required. Add ELEVENLABS_API_KEY in Vercel.",
                pct: "N/A",
                level: "warn",
                col: "#ffb340",
                dot: "#ffb340",
              },
              {
                name: "Speech Transcription",
                desc: "Whisper API key required. Add OPENAI_API_KEY in Vercel.",
                pct: "N/A",
                level: "warn",
                col: "#ffb340",
                dot: "#ffb340",
              },
              {
                name: "Audio Integrity",
                desc: "Full audio analysis requires backend configuration.",
                pct: "N/A",
                level: "warn",
                col: "#ffb340",
                dot: "#ffb340",
              },
              {
                name: "Content Analysis",
                desc: "Configure backend to enable real-time voice analysis.",
                pct: "N/A",
                level: "warn",
                col: "#ffb340",
                dot: "#ffb340",
              },
            ],
          },
          "[Audio Recording]"
        );
      }, 400);
      return;
    }

    // TEXT / URL MODE
    try {
      const ctrl = new AbortController();
      const t = setTimeout(() => ctrl.abort(), 30000);
      const res = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: inputVal }),
        signal: ctrl.signal,
      });
      clearTimeout(t);
      if (res.ok) {
        const d = await res.json();
        clearInterval(iv);
        setStep(3);
        setTimeout(() => {
          setStep(-1);
          finalize(d, inputVal);
        }, 400);
        return;
      }
    } catch (e) {}
    clearInterval(iv);
    setStep(3);
    setTimeout(() => {
      setStep(-1);
      finalize(analyzeLocally(inputVal), inputVal);
    }, 400);
  };

  const doScan = () => {
    setScanError("");
    if (mode === "audio") {
      if (
        !audioBlobRef.current &&
        !audioName.includes("KB") &&
        !audioName.includes("captured")
      ) {
        setScanError("Please record audio or upload a file first.");
        return;
      }
      runAnalysis("audio", audioName);
      return;
    }
    const inp = mode === "text" ? text.trim() : url.trim();
    if (!inp) {
      setScanError(
        mode === "text"
          ? "Please paste or type some text to analyze."
          : "Please enter a URL to scan."
      );
      return;
    }
    if (inp.length < 5) {
      setScanError("Content is too short to analyze.");
      return;
    }
    runAnalysis(mode, inp);
  };

  const chunksRef = useRef([]);
  const audioBlobRef = useRef(null);

  const toggleRecording = async () => {
    if (recording) {
      if (mediaRef.current) {
        mediaRef.current.stop();
        mediaRef.current.stream?.getTracks().forEach((t) => t.stop());
      }
      setRecording(false);
      return;
    }
    try {
      chunksRef.current = [];
      audioBlobRef.current = null;
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream, { mimeType: "audio/webm" });
      mr.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };
      mr.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: "audio/webm" });
        audioBlobRef.current = blob;
        setAudioName(`Recording ready (${(blob.size / 1024).toFixed(1)}KB)`);
      };
      mediaRef.current = mr;
      mr.start(100);
      setRecording(true);
      setAudioName("");
    } catch (e) {
      setAudioName("Mic access denied — using demo mode");
      setRecording(false);
    }
  };
  const handleFileUpload = (e) => {
    const f = e.target.files[0];
    if (f) setAudioName(f.name);
  };

  /* analyzing overlay */
  if (step >= 0)
    return (
      <div
        style={{
          minHeight: "100vh",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          background: C.bg,
          gap: 28,
          padding: 40,
        }}
      >
        <style>{`@keyframes spinAnim{to{transform:rotate(360deg)}}`}</style>
        <div style={{ position: "relative", width: 120, height: 120 }}>
          <div
            style={{
              position: "absolute",
              inset: 0,
              borderRadius: "50%",
              border: `2px solid ${C.border}`,
            }}
          />
          <div
            style={{
              position: "absolute",
              top: 10,
              left: 10,
              right: 10,
              bottom: 10,
              borderRadius: "50%",
              border: "1px solid rgba(200,255,0,0.3)",
              animation: "spinAnim 2.5s linear infinite",
            }}
          />
          <div
            style={{
              position: "absolute",
              top: 24,
              left: 24,
              right: 24,
              bottom: 24,
              borderRadius: "50%",
              border: "2px solid #c8ff00",
              animation: "spinAnim 1.5s linear infinite reverse",
            }}
          />
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <AppLogo size={42} glow={true} />
          </div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div
            style={{
              fontFamily: "var(--mono)",
              fontSize: 10,
              letterSpacing: 3,
              textTransform: "uppercase",
              color: C.accent,
              marginBottom: 8,
            }}
          >
            Analyzing
          </div>
          <div style={{ fontSize: 14, color: C.text, fontWeight: 500 }}>
            {STEPS[step]}
          </div>
        </div>
        <div style={{ display: "flex", gap: 6 }}>
          {STEPS.map((_, i) => (
            <div
              key={i}
              style={{
                width: i === step ? 24 : 6,
                height: 6,
                borderRadius: 3,
                background:
                  i === step
                    ? C.accent
                    : i < step
                    ? "rgba(200,255,0,0.3)"
                    : C.border,
                transition: "all .4s",
              }}
            />
          ))}
        </div>
      </div>
    );

  const pct = Math.round((scansUsed / MAX_SCANS) * 100);

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        background: C.bg,
      }}
    >
      <Nav right="SCAN" />
      <div style={{ padding: "18px 20px 110px" }}>
        {scansUsed >= MAX_SCANS && (
          <UpBanner msg="You've used all 5 free scans today." />
        )}

        {/* scan counter */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: 18,
          }}
        >
          <span className="label">Daily Scans</span>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div
              style={{
                width: 100,
                height: 4,
                background: C.border,
                borderRadius: 2,
                overflow: "hidden",
              }}
            >
              <div
                style={{
                  height: "100%",
                  width: `${pct}%`,
                  background:
                    pct >= 100 ? C.danger : pct >= 70 ? C.warn : C.accent,
                  borderRadius: 2,
                  transition: "width .5s",
                }}
              ></div>
            </div>
            <span
              style={{
                fontFamily: "var(--mono)",
                fontSize: 11,
                color: pct >= 100 ? C.danger : C.text,
                fontWeight: 600,
              }}
            >
              {scansUsed}
              <span style={{ color: C.muted }}>/{MAX_SCANS}</span>
            </span>
          </div>
        </div>

        {/* mode tabs */}
        <div
          style={{
            display: "flex",
            gap: 6,
            marginBottom: 16,
            background: C.panel,
            borderRadius: 12,
            padding: 4,
            border: `1px solid ${C.border}`,
          }}
        >
          {[
            { id: "text", label: "Text", ico: P.scan },
            { id: "url", label: "URL", ico: P.url },
            { id: "audio", label: "Audio", ico: P.micro },
          ].map((m) => (
            <button
              key={m.id}
              onClick={() => {
                setMode(m.id);
                setScanError("");
              }}
              style={{
                flex: 1,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 6,
                padding: "10px 0",
                background:
                  mode === m.id ? "rgba(200,255,0,0.1)" : "transparent",
                border:
                  mode === m.id
                    ? "1px solid rgba(200,255,0,0.25)"
                    : "1px solid transparent",
                borderRadius: 9,
                cursor: "pointer",
                color: mode === m.id ? C.accent : C.muted,
                fontFamily: "var(--mono)",
                fontSize: 10,
                letterSpacing: 1,
                textTransform: "uppercase",
                transition: "all .2s",
                fontWeight: mode === m.id ? 600 : 400,
              }}
            >
              <Ico d={m.ico} s={14} c={mode === m.id ? C.accent : C.muted} />
              {m.label}
            </button>
          ))}
        </div>

        {/* input area */}
        {mode === "text" && (
          <textarea
            className="inp"
            placeholder="Paste news article, social media post, or any content to analyze..."
            value={text}
            onChange={(e) => {
              setText(e.target.value.slice(0, 5000));
              setScanError("");
            }}
            style={{
              padding: "14px 16px",
              minHeight: 160,
              resize: "vertical",
              lineHeight: 1.6,
              fontSize: 14,
            }}
          />
        )}
        {mode === "url" && (
          <div style={{ position: "relative" }}>
            <div
              style={{
                position: "absolute",
                left: 14,
                top: "50%",
                transform: "translateY(-50%)",
              }}
            >
              <Ico d={P.url} s={16} c={C.muted} />
            </div>
            <input
              className="inp"
              type="url"
              placeholder="https://example.com/article"
              value={url}
              onChange={(e) => {
                setUrl(e.target.value);
                setScanError("");
              }}
              style={{ padding: "14px 14px 14px 44px" }}
            />
          </div>
        )}
        {mode === "audio" && (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <button
              onClick={toggleRecording}
              style={{
                padding: "18px",
                background: recording
                  ? "rgba(255,59,92,0.1)"
                  : "rgba(200,255,0,0.06)",
                border: `1px solid ${
                  recording ? C.danger : "rgba(200,255,0,0.2)"
                }`,
                borderRadius: 12,
                cursor: "pointer",
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 8,
                color: recording ? C.danger : C.accent,
              }}
            >
              <Ico d={P.micro} s={28} c={recording ? C.danger : C.accent} />
              <span
                style={{
                  fontFamily: "var(--mono)",
                  fontSize: 10,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                }}
              >
                {recording ? "● Recording — Tap to Stop" : "Tap to Record"}
              </span>
            </button>
            <button
              onClick={() => fileRef.current?.click()}
              style={{
                padding: "14px",
                background: "transparent",
                border: `1px dashed ${C.border}`,
                borderRadius: 12,
                cursor: "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 8,
                color: C.muted,
              }}
            >
              <Ico d={P.upload} s={18} c={C.muted} />
              <span
                style={{
                  fontFamily: "var(--mono)",
                  fontSize: 10,
                  letterSpacing: 1,
                  textTransform: "uppercase",
                }}
              >
                Upload Audio File
              </span>
            </button>
            <input
              ref={fileRef}
              type="file"
              accept="audio/*"
              style={{ display: "none" }}
              onChange={handleFileUpload}
            />
            {audioName && (
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  padding: "10px 14px",
                  background: "rgba(200,255,0,0.05)",
                  border: "1px solid rgba(200,255,0,0.2)",
                  borderRadius: 10,
                }}
              >
                <Ico d={P.check} s={14} c={C.accent} />
                <span
                  style={{
                    fontSize: 12,
                    color: C.accent,
                    fontFamily: "var(--mono)",
                  }}
                >
                  {audioName}
                </span>
              </div>
            )}
          </div>
        )}

        {/* analysis chips */}
        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: 8,
            marginTop: 14,
            marginBottom: 16,
          }}
        >
          {Object.entries(chips).map(([label, on]) => (
            <button
              key={label}
              onClick={() =>
                setChips((c) => {
                  const n = { ...c };
                  n[label] = !n[label];
                  return n;
                })
              }
              style={{
                padding: "6px 12px",
                borderRadius: 100,
                cursor: "pointer",
                background: on ? "rgba(200,255,0,0.08)" : "transparent",
                border: `1px solid ${on ? "rgba(200,255,0,0.3)" : C.border}`,
                color: on ? C.accent : C.muted,
                fontFamily: "var(--mono)",
                fontSize: 9,
                letterSpacing: 1.5,
                textTransform: "uppercase",
                transition: "all .2s",
              }}
            >
              {label}
            </button>
          ))}
        </div>

        {/* validation error */}
        {scanError && (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 10,
              padding: "12px 16px",
              marginBottom: 14,
              borderRadius: 12,
              background: "rgba(255,59,92,0.07)",
              border: "1px solid rgba(255,59,92,0.25)",
            }}
          >
            <Ico d={P.danger} s={16} c="#ff3b5c" />
            <span
              style={{
                fontSize: 13,
                color: "#ff3b5c",
                fontWeight: 500,
                lineHeight: 1.4,
              }}
            >
              {scanError}
            </span>
          </div>
        )}

        <button
          onClick={doScan}
          disabled={scansUsed >= MAX_SCANS}
          className="btn-p"
          style={{
            width: "100%",
            padding: "17px 0",
            fontSize: 14,
            letterSpacing: 0.5,
            borderRadius: 14,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 8,
            boxShadow:
              scansUsed >= MAX_SCANS
                ? "none"
                : "0 4px 24px rgba(200,255,0,0.25)",
          }}
        >
          <Ico
            d={P.scan}
            s={18}
            c={scansUsed >= MAX_SCANS ? "#5a6475" : "#070a0f"}
          />
          {scansUsed >= MAX_SCANS ? "Limit Reached — Upgrade" : "Scan Now"}
        </button>
      </div>
      <BNav active="scan" go={go} />
    </div>
  );
}

/* ══════════════════════════════════════════
   RESULT
══════════════════════════════════════════ */
function ResultScreen({ result, go }) {
  const type = result?.type || "warn";
  const color =
    type === "danger" ? C.danger : type === "warn" ? C.warn : C.safe;
  const bg =
    type === "danger"
      ? "rgba(255,59,92,0.07)"
      : type === "warn"
      ? "rgba(255,179,64,0.07)"
      : "rgba(0,230,118,0.07)";
  const brd =
    type === "danger"
      ? "rgba(255,59,92,0.25)"
      : type === "warn"
      ? "rgba(255,179,64,0.25)"
      : "rgba(0,230,118,0.25)";
  const fallback = RISK[type];
  const score = result?.score ?? fallback.score;
  const title = result?.title || fallback.title;
  const desc = result?.desc || fallback.desc;
  const isAI = !!(result?.title && result?.signals?.length);
  const hasURL = !!(result?.input && result.input.match(/https?:\/\//));
  const rawSignals = result?.signals?.length
    ? result.signals
    : fallback.signals;
  const signals = rawSignals.map((s) => {
    const isSrc =
      s.name?.toLowerCase().includes("source") ||
      s.name?.toLowerCase().includes("credibility");
    if (isSrc && !hasURL)
      return {
        ...s,
        desc: "No source URL provided — credibility not evaluated for this scan.",
        pct: "N/A",
        col: C.muted,
        dot: C.muted,
      };
    return s;
  });

  const scanId = result?.scanId || "#DEMO01";
  const scanTime =
    result?.timestamp ||
    new Date().toLocaleString("en-US", {
      month: "short",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
    });

  const [filled, setFilled] = useState(false);
  const [showMethod, setShowMethod] = useState(false);
  useEffect(() => {
    const t = setTimeout(() => setFilled(true), 200);
    return () => clearTimeout(t);
  }, [result]);

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        background: C.bg,
      }}
    >
      <Nav onBack={() => go("scan")} right="RESULT" />
      <div style={{ padding: "18px 20px 110px" }}>
        {/* badges */}
        <div
          style={{
            display: "flex",
            gap: 8,
            marginBottom: 14,
            flexWrap: "wrap",
            alignItems: "center",
          }}
        >
          {isAI && (
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                padding: "5px 11px",
                borderRadius: 100,
                background: "rgba(0,212,255,0.08)",
                border: "1px solid rgba(0,212,255,0.2)",
              }}
            >
              <div
                style={{
                  width: 5,
                  height: 5,
                  borderRadius: "50%",
                  background: C.accent2,
                  animation: "lgSpin .8s linear infinite",
                }}
              />
              <span
                style={{
                  fontFamily: "var(--mono)",
                  fontSize: 8,
                  letterSpacing: 2,
                  textTransform: "uppercase",
                  color: C.accent2,
                }}
              >
                AuthentiScan Analysis Engine
              </span>
            </div>
          )}
          {result?.verdict && (
            <div
              style={{
                padding: "5px 11px",
                borderRadius: 100,
                fontFamily: "var(--mono)",
                fontSize: 9,
                letterSpacing: 2,
                textTransform: "uppercase",
                fontWeight: 700,
                background:
                  result.verdict === "fake"
                    ? "rgba(255,59,92,0.1)"
                    : result.verdict === "real"
                    ? "rgba(0,230,118,0.1)"
                    : "rgba(255,179,64,0.1)",
                border: `1px solid ${
                  result.verdict === "fake"
                    ? "rgba(255,59,92,0.3)"
                    : result.verdict === "real"
                    ? "rgba(0,230,118,0.3)"
                    : "rgba(255,179,64,0.3)"
                }`,
                color:
                  result.verdict === "fake"
                    ? C.danger
                    : result.verdict === "real"
                    ? C.safe
                    : C.warn,
              }}
            >
              {result.verdict === "fake"
                ? "⚠ FAKE"
                : result.verdict === "real"
                ? "✓ VERIFIED"
                : result.verdict === "misleading"
                ? "⚡ MISLEADING"
                : "? UNVERIFIED"}
            </div>
          )}
        </div>

        {/* scan metadata */}
        <div
          style={{
            display: "flex",
            marginBottom: 14,
            background: C.panel,
            border: `1px solid ${C.border}`,
            borderRadius: 12,
            overflow: "hidden",
          }}
        >
          {[
            ["SCAN ID", scanId],
            ["TIME", scanTime],
            ["ENGINE", "v2.0"],
          ].map(([l, v], i) => (
            <div
              key={i}
              style={{
                flex: 1,
                padding: "10px 12px",
                borderRight: i < 2 ? `1px solid ${C.border}` : "none",
              }}
            >
              <div className="label" style={{ marginBottom: 3 }}>
                {l}
              </div>
              <div
                style={{
                  fontFamily: "var(--mono)",
                  fontSize: 10,
                  fontWeight: 700,
                  color: C.accent,
                  letterSpacing: 0.5,
                }}
              >
                {v}
              </div>
            </div>
          ))}
        </div>

        {/* main score card */}
        <div
          style={{
            background: bg,
            border: `1px solid ${brd}`,
            borderRadius: 14,
            padding: 18,
            marginBottom: 12,
            position: "relative",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              position: "absolute",
              top: 0,
              left: 0,
              width: 4,
              height: "100%",
              background: color,
              borderRadius: "2px 0 0 2px",
            }}
          />
          <div
            style={{
              display: "flex",
              alignItems: "flex-start",
              justifyContent: "space-between",
              marginBottom: 14,
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <div
                style={{
                  width: 44,
                  height: 44,
                  borderRadius: "50%",
                  background: `${color}18`,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <Ico d={P[type]} s={22} c={color} />
              </div>
              <div>
                <div className="label" style={{ marginBottom: 3 }}>
                  Risk Assessment
                </div>
                <div
                  style={{
                    fontSize: 17,
                    fontWeight: 700,
                    color,
                    lineHeight: 1.2,
                  }}
                >
                  {title}
                </div>
              </div>
            </div>
            <div style={{ textAlign: "right", flexShrink: 0 }}>
              <div
                style={{
                  fontSize: 48,
                  fontWeight: 800,
                  color,
                  lineHeight: 1,
                  fontFamily: "var(--font)",
                }}
              >
                {score}
              </div>
              <div className="label">Risk Index</div>
            </div>
          </div>
          {result?.summary && (
            <div
              style={{
                background: "rgba(200,255,0,0.04)",
                border: "1px solid rgba(200,255,0,0.1)",
                borderRadius: 8,
                padding: "10px 12px",
                marginBottom: 12,
                fontSize: 12,
                color: "rgba(240,244,248,0.75)",
                lineHeight: 1.6,
                fontStyle: "italic",
              }}
            >
              "{stripCites(result.summary)}"
            </div>
          )}
          <p
            style={{
              fontSize: 13,
              lineHeight: 1.8,
              color: "rgba(240,244,248,0.75)",
              marginBottom: 14,
            }}
          >
            {stripCites(desc)}
          </p>
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              marginBottom: 5,
            }}
          >
            <span className="label">Low Risk</span>
            <span className="label">High Risk</span>
          </div>
          <div
            style={{
              height: 4,
              background: C.border,
              borderRadius: 2,
              overflow: "hidden",
            }}
          >
            <div
              style={{
                height: "100%",
                width: filled ? `${score}%` : "0%",
                background: color,
                borderRadius: 2,
                transition: "width 1.2s ease",
              }}
            />
          </div>
        </div>

        {/* why this score */}
        <button
          onClick={() => setShowMethod((m) => !m)}
          style={{
            width: "100%",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            padding: "11px 14px",
            marginBottom: 10,
            background: "rgba(200,255,0,0.04)",
            border: "1px solid rgba(200,255,0,0.1)",
            borderRadius: 10,
            cursor: "pointer",
            color: C.text,
          }}
        >
          <span
            style={{
              fontFamily: "var(--mono)",
              fontSize: 9,
              letterSpacing: 2,
              textTransform: "uppercase",
              color: C.accent,
            }}
          >
            ⚙ Why this score?
          </span>
          <span style={{ color: C.muted, fontSize: 11 }}>
            {showMethod ? "▲" : "▼"}
          </span>
        </button>
        {showMethod && (
          <div
            style={{
              background: C.panel,
              border: `1px solid ${C.border}`,
              borderRadius: 10,
              padding: "14px 16px",
              marginBottom: 10,
              fontSize: 12,
              color: C.muted,
              lineHeight: 1.8,
            }}
          >
            <div
              className="label"
              style={{ color: C.accent2, marginBottom: 8 }}
            >
              Composite Risk Index Methodology
            </div>
            <div style={{ marginBottom: 8 }}>
              Weighted average of 4 signal categories:
            </div>
            {[
              [
                "Claim Accuracy",
                "35%",
                "Verifies stated facts against known data",
              ],
              [
                "Source Credibility",
                "25%",
                "Evaluates URL domain and citation quality",
              ],
              [
                "Emotional Intensity",
                "25%",
                "Detects manipulation language patterns",
              ],
              [
                "Context Completeness",
                "15%",
                "Checks for missing context or framing bias",
              ],
            ].map(([n, w, d]) => (
              <div key={n} style={{ display: "flex", gap: 8, marginBottom: 4 }}>
                <span
                  style={{
                    color: C.accent,
                    fontFamily: "var(--mono)",
                    fontSize: 10,
                    fontWeight: 700,
                    flexShrink: 0,
                    minWidth: 30,
                  }}
                >
                  {w}
                </span>
                <span>
                  <span style={{ color: C.text }}>{n}</span> — {d}
                </span>
              </div>
            ))}
            <div
              style={{
                marginTop: 10,
                paddingTop: 8,
                borderTop: `1px solid ${C.border}`,
                fontFamily: "var(--mono)",
                fontSize: 8,
                letterSpacing: 1,
                color: "rgba(200,255,0,0.4)",
              }}
            >
              ≥65 HIGH RISK · 35–64 VERIFY · &lt;35 LOW RISK
            </div>
          </div>
        )}

        {/* signals */}
        <div className="label" style={{ marginBottom: 8 }}>
          Analysis Signals
        </div>
        {signals.map((sig, i) => (
          <div
            key={i}
            style={{
              background: C.panel,
              border: `1px solid ${C.border}`,
              borderRadius: 12,
              padding: "13px 15px",
              marginBottom: 8,
              display: "flex",
              alignItems: "flex-start",
              gap: 12,
            }}
          >
            <div
              style={{
                width: 7,
                height: 7,
                borderRadius: "50%",
                background: sig.dot || sig.col || C.muted,
                marginTop: 4,
                flexShrink: 0,
              }}
            />
            <div style={{ flex: 1 }}>
              <div
                style={{
                  fontFamily: "var(--mono)",
                  fontSize: 9,
                  letterSpacing: 1,
                  textTransform: "uppercase",
                  color: C.text,
                  marginBottom: 3,
                }}
              >
                {sig.name}
              </div>
              <div style={{ fontSize: 12, color: C.muted, lineHeight: 1.6 }}>
                {stripCites(sig.desc)}
              </div>
            </div>
            <div
              style={{
                fontFamily: "var(--mono)",
                fontSize: 12,
                fontWeight: 700,
                color: sig.pct === "N/A" ? C.muted : sig.col || C.muted,
                flexShrink: 0,
                background:
                  sig.pct === "N/A" ? "rgba(90,100,117,0.15)" : "transparent",
                padding: sig.pct === "N/A" ? "2px 7px" : "0",
                borderRadius: sig.pct === "N/A" ? 4 : 0,
                border:
                  sig.pct === "N/A"
                    ? `1px solid rgba(90,100,117,0.25)`
                    : "none",
              }}
            >
              {sig.pct}
            </div>
          </div>
        ))}

        <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
          <button
            onClick={() => go("history")}
            style={{
              flex: 1,
              padding: 14,
              background: C.panel,
              border: `1px solid ${C.border}`,
              borderRadius: 12,
              color: C.text,
              fontFamily: "var(--mono)",
              fontSize: 9,
              letterSpacing: 2,
              textTransform: "uppercase",
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 6,
            }}
          >
            <Ico d={P.save} s={14} c={C.accent} /> Save
          </button>
          <button
            style={{
              flex: 1,
              padding: 14,
              background: C.panel,
              border: `1px solid ${C.border}`,
              borderRadius: 12,
              color: C.text,
              fontFamily: "var(--mono)",
              fontSize: 9,
              letterSpacing: 2,
              textTransform: "uppercase",
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 6,
            }}
          >
            <Ico d={P.share} s={14} c={C.accent} /> Share
          </button>
        </div>
      </div>
      <BNav active="result" go={go} />
    </div>
  );
}

