/* ══════════════════════════════════════════
   APP ROOT
══════════════════════════════════════════ */
export default function App() {
  const [screen, setScreen] = useState("splash");
  const [loggedIn, setLoggedIn] = useState(false);
  const [result, setResult] = useState(null);
  const [history, setHistory] = useState([]);
  const [scansUsed, setScansUsed] = useState(0);

  const go = (s) => setScreen(s);

  const handleResult = (r) => {
    setResult(r);
    setHistory((h) => [
      {
        text: r.input?.slice(0, 60) || "Scan result",
        type: r.type,
        score: r.score,
        time:
          r.timestamp ||
          new Date().toLocaleString("en-US", {
            month: "short",
            day: "2-digit",
            hour: "2-digit",
            minute: "2-digit",
          }),
      },
      ...h.slice(0, 49),
    ]);
    go("result");
  };

  return (
    <>
      <GlobalStyles />
      <div
        style={{
          maxWidth: 430,
          margin: "0 auto",
          minHeight: "100vh",
          background: C.bg,
          position: "relative",
        }}
      >
        {screen === "splash" && (
          <Splash onEnter={() => go("scan")} onLogin={() => go("login")} />
        )}
        {screen === "login" && (
          <LoginScreen
            onLogin={() => {
              setLoggedIn(true);
              go("scan");
            }}
            onGuest={() => go("scan")}
          />
        )}
        {screen === "scan" && (
          <ScanScreen
            go={go}
            setResult={handleResult}
            scansUsed={scansUsed}
            setScansUsed={setScansUsed}
          />
        )}
        {screen === "result" && <ResultScreen result={result} go={go} />}
        {screen === "history" && <HistoryScreen go={go} history={history} />}
        {screen === "profile" && (
          <ProfileScreen
            go={go}
            onLogout={() => {
              setLoggedIn(false);
              go("splash");
            }}
            scansUsed={scansUsed}
          />
        )}
      </div>
    </>
  );
}
